    /*
      DEFAULT  ：默认会激活新创建的节点，并且进入编辑模式。如果同时创建了多个新节点，那么只会激活而不会进入编辑模式
      NOT_ACTIVE  : 不激活新创建的节点
      ACTIVE_ONLY  : 只激活新创建的节点，不进入编辑模式
    */
    createNewNodeBehavior: constant_1.CONSTANTS.CREATE_NEW_NODE_BEHAVIOR.DEFAULT,
