    // 接收svg path字符串，返回svg节点
    customCreateNodePath: null,
    // 菱形、平行四边形、八角矩形、外三角矩形、内三角矩形等形状会调用该方法
    // 接收points数组点位，返回svg节点
    customCreateNodePolygon: null,
